// Enum declaration
enum Day {
    MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY, SATURDAY, SUNDAY
}

// Enum with fields and methods
enum Planet {
    MERCURY(3.30e23, 2.44e6),
    VENUS(4.87e24, 6.05e6),
    EARTH(5.97e24, 6.37e6),
    MARS(6.42e23, 3.39e6),
    JUPITER(1.90e27, 6.99e7),
    SATURN(5.68e26, 5.82e7),
    URANUS(8.68e25, 2.54e7),
    NEPTUNE(1.02e26, 2.47e7);

    private final double mass;      // in kg
    private final double radius;    // in meters

    Planet(double mass, double radius) {
        this.mass = mass;
        this.radius = radius;
    }

    public double getMass() {
        return mass;
    }

    public double getRadius() {
        return radius;
    }

    public double getSurfaceGravity() {
        return 6.67e-11 * mass / (radius * radius);
    }
}

// Enum with custom methods
enum Status {
    PENDING, PROCESSING, COMPLETED, FAILED;

    // Enum can have methods
    public boolean isFinished() {
        return this == COMPLETED || this == FAILED;
    }
}

public class EnumExample {
    public static void main(String[] args) {
        // Basic enum usage
        Day today = Day.FRIDAY;
        System.out.println("Today: " + today);

        // Using in switch
        System.out.println("--- Switch ---");
        switch (today) {
            case MONDAY:
                System.out.println("Start of week");
                break;
            case FRIDAY:
                System.out.println("TGIF!");
                break;
            case SATURDAY:
            case SUNDAY:
                System.out.println("Weekend!");
                break;
            default:
                System.out.println("Midweek");
        }

        // Enum methods
        System.out.println("--- Enum methods ---");
        for (Day d : Day.values()) {
            System.out.println(d + " ordinal: " + d.ordinal());
        }

        Day parsed = Day.valueOf("MONDAY");
        System.out.println("Parsed: " + parsed);

        // Enum with fields
        System.out.println("--- Planets ---");
        System.out.printf("Earth mass: %.2e kg%n", Planet.EARTH.getMass());
        System.out.printf("Earth gravity: %.2f m/s²%n", Planet.EARTH.getSurfaceGravity());

        for (Planet p : Planet.values()) {
            System.out.printf("%s: gravity = %.2f m/s²%n", p, p.getSurfaceGravity());
        }

        // Status enum
        Status status = Status.PROCESSING;
        System.out.println("Is finished? " + status.isFinished());
        System.out.println("COMPLETED finished? " + Status.COMPLETED.isFinished());
    }
}

